import{_ as e,o as r,c as d,a2 as a}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"董事长信 - 1987","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1987年/翻译.md","filePath":"01_letters/1987年/翻译.md"}'),p={name:"01_letters/1987年/翻译.md"};function o(s,t,i,n,l,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="董事长信-1987" tabindex="-1">董事长信 - 1987 <a class="header-anchor" href="#董事长信-1987" aria-label="Permalink to &quot;董事长信 - 1987&quot;">​</a></h1><p>1988年2月29日</p><p>致伯克希尔·哈撒韦公司全体股东：</p><p>1987年我们净值增长4.64亿美元，增长19.5%，过去二十三年（现任管理层接手以来）每股账面价值从19.46美元涨到2477.47美元，年复利23.1%。当然，真正重要的是每股 business 内在价值增长，不是账面价值，很多公司账面价值和内在价值几乎完全无关，比如LTV和Baldwin-United破产前，年报账面价值分别还有6.52亿和3.97亿，反过来，Belridge Oil 1979年卖给壳牌，账面价值才1.77亿，卖了36亿。</p><p>伯克希尔不一样，账面价值和内在价值一直跟踪得不错，过去十年 business 内在价值增长一直适度超过账面价值增长，1987年依然这样，好消息还在继续。</p><p>内在价值对账面价值溢价扩大，原因很简单：我们拥有一些卓越 business，这些 business 由更卓越的经理运营。</p><p>你当然可以质疑这个说法，CEO很少告诉股东，我们汇集了一群 turkey 经营业务，他们不愿意这么说，所以年报常常很奇怪，有时候，CEO年报写几页，说业绩差得不像话，最后一段还是暖人心地说，我们经理团队&quot;我们最宝贵资产就是我们人，你不禁想问，其他资产是什么呢？</p><p>伯克希尔，我对我们运营经理评价，说轻了，为什么，你看第七页，我们七个最大非金融业务，历史成本会计算，税前盈利加起来税前1.8亿美元，这七个业务，负债几乎可以忽略，1987年净利息费用才200万美元，所以税前股权资本投入1.75亿，税前赚1.78亿，税后大约1亿美元，ROE 57%。</p><p>你很少看到这个数字很少见，多元化大公司，名义杠杆很小，《财富》1988投资者指南说，过去十年平均ROE超过30%的，一千大公司一共只有二十五家，第一是Commerce Clearing House 40.2%，最高。</p><p>当然，伯克希尔从这七个业务拿到的回报没这么高，因为我们买的时候买价相对于 underlying 资本，账面有溢价，所以我们账面有2.22亿溢价，但是评价经理，应该看他们对 underlying 资产赚多少钱，我们付多少钱不影响经理要用多少资本工作，就像，你买Commerce Clearing House股票，你付六倍账面价值，不影响CCH自己ROE不会变。</p><p>所以我们可以得到三个结论： 第一，这七个业务当前 business 价值，远远高于历史账面价值，也远远高于伯克希尔资产负债表账面价值。 第二，因为运营这些业务只需要很少资本，所以它们增长的时候，几乎所有盈利都可以拿去投资新机会。 第三，这些业务真的 extraordinary 就是 extraordinary 经理运营，把不寻常才能品格，不寻常才能品格，才能拿到 exceptional 财务结果。</p><p>我们和这些经理合作，预期本来就很高，结果每次都超过我们预期，我们得到比我们应得更多，我们愿意接受这种不公平。</p><p>除了七个圣人般的七个业务，我们还有保险，我认为保险 business 价值也高于投入净资产，当然，财险公司估值相当不精确，行业波动，报告收益常常严重不准，新税法未来还会严重伤害未来盈利能力，尽管有这些问题，我们喜欢这个生意，未来几乎肯定还是我们最大业务，迈克·戈德堡管理，长期会对我们很好。</p><p>有这样经理，我合伙人查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>，我对运营几乎没什么事，事实上，公平说，如果我们做多，我们做成这样，更少做成更少，我们没有公司会议，公司预算，也没有绩效回顾（当然经理自己单位这些流程当然有用），我们对<a href="/04_people/B夫人.html">B夫人</a>家族不懂家具，对赫尔德曼不懂制服，我们能做什么贡献？就是鼓掌，我们不会告诉你，这种就是我们做法，没有用，就是我们鼓掌，这种不是波利安娜不分青红皂白鼓掌，我们查理和我看过太多 ordinary 商业 performance，真的，对 virtuoso performance 只有一个反应，就是持续震耳欲聋鼓掌。</p><h2 id="报告收益来源" tabindex="-1">报告收益来源 <a class="header-anchor" href="#报告收益来源" aria-label="Permalink to &quot;报告收益来源&quot;">​</a></h2><p>下页表格显示伯克希尔，商誉摊销和其他购买价格会计调整不对具体业务，所以我们单独汇总，我们觉得这种 presentation，对投资者经理比标准GAAP更有用，所以这么做。</p><table tabindex="0"><thead><tr><th></th><th><strong>税前收益</strong></th><th></th></tr></thead><tbody><tr><td></td><td>1987</td><td>1986</td></tr><tr><td><strong>营业收益：</strong></td><td></td><td></td></tr><tr><td><strong>保险集团：</strong></td><td></td><td></td></tr><tr><td>承保</td><td>$(55,429)</td><td>$(55,844)</td></tr><tr><td>净投资收益</td><td>152,483</td><td>107,143</td></tr><tr><td>水牛城新闻</td><td>39,410</td><td>34,736</td></tr><tr><td>Fechheimer（1986年6月3日收购</td><td>13,332</td><td>8,400</td></tr><tr><td>Kirby</td><td>22,408</td><td>20,218</td></tr><tr><td>内布拉斯加家具城</td><td>16,837</td><td>17,685</td></tr><tr><td>Scott Fetzer多元化制造</td><td>30,591</td><td>25,358</td></tr><tr><td>喜诗糖果</td><td>31,693</td><td>30,347</td></tr><tr><td>韦斯考非保险</td><td>6,209</td><td>4,978</td></tr><tr><td>世界图书</td><td>25,745</td><td>21,978</td></tr><tr><td>商誉摊销</td><td>(2,862)</td><td>(2,555)</td></tr><tr><td>其他购买价格会计调整</td><td>(5,546)</td><td>(10,033)</td></tr><tr><td>债务利息提前还款罚息</td><td>(11,474)</td><td>(10,033)</td></tr><tr><td>股东指定捐赠</td><td>(4,938)</td><td>(3,997)</td></tr><tr><td>其他</td><td>22,460</td><td>20,770</td></tr><tr><td><strong>营业收益合计</strong></td><td>280,919</td><td>195,857</td></tr><tr><td>证券出售</td><td>27,319</td><td>216,242</td></tr><tr><td><strong>所有主体总收益</strong></td><td>$308,238</td><td>$412,099</td></tr></tbody></table><p>就像吉普赛玫瑰李说的，&quot;我去年什么都有，就是都缩水两寸&quot;，表格显示，1987年我们几乎所有业务都增长了，没什么新东西，这是好事不是坏事，剧烈变化和超额回报通常不搭，大多数投资者觉得，追求刺激变化，未来，普通人，都给变化快的生意，给最高PE，谁不喜欢平淡无奇，邻家女孩，再吸引人也比不上，不管她多好。</p><p>经验表明，最好 business 回报通常来自一直做差不多事，和五十年前十五年做的一样，剧烈变化，经常有大错机会，不断剧烈变化很难建立坚固 business 护城河，坚固护城河才是持续高回报关键。</p><p>《财富》研究支持我们观点：1977-1986十年，平均ROE超过20%，每年最差不低于15%，满足这两个条件一共25家企业，这25家不仅是商业明星，股市也表现好，十年都跑赢标普500。</p><p>这25家让你惊讶两点：第一，大多数都是平淡行业，没什么高科技，大多不性感，就是卖普通产品服务，十年前就这样，现在还是这样；第二，它们大多数很少杠杆，很少借很多负债，大多数本来就这样做，你只要把已经很强 business 做好，集中在一个赢家主题，不要 diversification 不对，就是做好已经很强业务，把做到极致，就是 exceptional 盈利。</p><p>伯克希尔经验也类似，我们经理 extraordinary 结果来自做 ordinary ordinary things 做得 exceptional 好，我们经理保护好自己 franchise，控制成本，不做不相关多元化，就这样，我们就这样，结果显示出来了。</p><p>更新一下：</p><ul><li>阿加莎·克里斯蒂说考古学家丈夫职业完美，&quot;你越老，大家越对你感兴趣，所以商人也应该懂，94岁<a href="/04_people/B夫人.html">B夫人</a>，内布拉斯加家具城董事长，现在还比年轻人厉害，五十年前<a href="/04_people/B夫人.html">B夫人</a>五百块开始做生意，现在NFM已经远远是美国最大单店家居商店，<a href="/04_people/B夫人.html">B夫人</a>依然一周七天上班，开门到关门，买货卖货管理，竞争对手都不是对手，越来越快，五年十年后还会更快。所以我说服董事会废除百岁强制退休政策，每年过了，对，年龄越大越觉得这套政策傻。</li></ul><p>1987年NFM净销售额1.426亿美元，增长8%，美国找不到第二家这样商店，<a href="/04_people/B夫人.html">B夫人</a>和她家族，整个家族都保持 business 本能，诚实勤奋，整个比谁都比不了，去年一位竞争对手匿名写信给我，&quot;告诉你，NFM每件东西都比别人便宜10-20%，一亿四千万销售额，就是两千八百万额外利润，不小啊，你们可以涨价赚更多，你们降价给顾客，你们错了。NFM就是 follow <a href="/04_people/B夫人.html">B夫人</a>格言，&quot;低价卖，说实话&quot;，所以一直增长繁荣。</p><ul><li>我们规模的 dominant 报纸，水牛城新闻，继续全国第一，两个重要指标，渗透率（每天周日渗透率，我们市场买报纸家庭百分比），第二新闻版面占比，我们都是第一。</li></ul><p>可能不是巧合，新闻多的产品，读者最欢迎，渗透率就高，我们一直保持50%新闻版面，哪怕利润下降我们也不会砍，查理和我不相信弹性预算，就是&quot;收入降五个百分点，我们就砍新闻，我们绝对不做，不管利润降不降价，我们不会做伤害产品质量的事情，我们就是这样，永远这样。</p><p>尽管我们收入1984年后增长很慢，<a href="/04_people/斯坦·利普西.html">斯坦·利普西</a>管理，利润增长非常好，过去我一直错预测利润率下降，今年我不预测了，1988新闻纸涨了，利润率肯定收缩，所以对的，我们不会因为这个就砍新闻。</p><ul><li><p>Fechheimer Bros 也是家族生意，就像<a href="/04_people/B夫人.html">B夫人</a>家族，什么神奇家族，三代赫尔德曼，现在依然增长，利润还创新高，未来看好，这个生意就是制服制造分销，没什么神奇，神奇的就是赫尔德曼家族，三代都懂生意，享受做生意，我们非常幸运和他们合伙。</p></li><li><p>喜诗，查克·哈金斯经营，去年总销量突破2500万磅不到一点，连续六年同店磅数基本不涨，几乎没变，实际上这已经是进步，过去六年每年都跌，所以稳住就是进步，1986年圣诞很好，1987年圣诞更好，所以稳住了，我们价格只涨了一点点，1988年我们涨价还是温和，今年利润可能不会增长。</p></li></ul><p>查克永远客户导向，整个公司文化就是这样，错了我们都看到了，比如去年我们砍掉14个产品，顾客反对，立刻加回去，还给每个人写信解释，这种对客户就是我们喜欢，所以喜诗现在这种客户导向，很少零售商能做到，所以非常难得。</p><ul><li>世界图书、Kirby、Scott Fetzer制造集团都归拉尔夫·谢伊管理，我只能说，我们买了之后，结果比我们预期还要好，1987年盈利涨10%，平均用资本还下降了，拉尔夫管十九个 business，每个都抓得住，还挖到好经理，我们太幸运了，还能再来几个这样收购。</li></ul><p>世界图书，1987年推出重大更新版本，比1962以来最大改了，彩色照片从一万四千涨到两万四千，六千多篇修改，八百多新作者，我推荐你们家里没有这套百科全书，真的很好，值得买。</p><h2 id="保险运营" tabindex="-1">保险运营 <a class="header-anchor" href="#保险运营" aria-label="Permalink to &quot;保险运营&quot;">​</a></h2><p>下面更新我们行业常用表格：</p><p>| 年份 | 保费写出增长率 | 法定综合成本率 | 已发生损失增长率 | GNP平减通胀 | |:----😐:--------------😐:----------------😐:-------------😐 | 1981 | 3.8% | 106.0 | 6.5% | 9.7% | | 1982 | 4.4% | 109.8 | 8.4% | 6.4% | | 1983 | 4.6% | 112.0 | 6.8% | 3.9% | | 1984 | 9.2% | 117.9 | 16.9% | 3.8% | | 1985 | 22.1% | 116.3 | 16.1% | 3.3% | | 1986 (修正) | 22.2% | 108.0 | 13.5% | 2.6% | | 1987 (估计) | 8.7% | 104.7 | 6.8% | 3.2% |</p><p>来源：Best保险管理报告</p><p>综合成本率低于100承保盈利，高于100承保亏损，加上浮存金投资收益，通常综合成本率107-111之间，股东资金赚不亏，不包含股东资金赚不亏，不包含股东资金赚钱。</p><p>保险行业数学很简单，每年保费增长一直4%5%，承保损失一定会涨，不是因为事故更多，也不是一般通胀，现在社会司法通胀才是主因，打官司成本爆炸，法官陪审团不断扩张保单保障范围，超过保险公司写保单时候预期，看不到这个趋势停不下来，所以我们一直说行业每年保费要涨接近10%才能 hold 盈利能力，哪怕整体通胀只有2%-4%。</p><p>1985-87保费大涨，所以1987承保业绩当然很好，但是好消息完了，派对结束，保费增长放缓，1988年肯定远低于我们均衡10%，显然，party 保费增长，价格上涨对盈利能力提升有滞后，所以1988行业综合成本率还会小幅提升，然后1988年底或者1989初改善结束，之后行业又会开始恶化。</p><p>保险行业 curse 就是糟糕长期 outlook：几百个竞争者，进入门槛低，产品没办法差异化，大宗商品一样生意，只有极低运营商，或者小众保护 niche 才能持续高盈利，短缺时候大宗商品生意才能好，短缺不会长久，资本主义有趣一点意思就是，短缺时候价格好，大部分经理就是忍不住扩产能，所以短缺就没了，我们保险经理也忍不住，所以什么历史教训就是，what we learn from history is that we do not learn from history，迪斯累利说的。</p><p>伯克希尔我们两个方法跳出大宗商品，两个方法差异化：第一我们靠财务 strength 差异化，我们比行业其他人都强，个人车险房子险，买家不用你就算保险公司破产，也赔不到你，没关系，商业险，买方不关心，反正出事大损失时候才知道，只有真出事才知道谁能赔，那时候我们优势才体现出来，所以买家会来找我们，我们就是最大优势就是我们不一样，我们随时能接大单，价格不对我们不接，价格对我们就接，所以我们就是 standby 容量，别人不敢接的时候我们来。</p><p>第二我们对 volume 完全无所谓，1988我们愿意写五倍业务，也愿意做五分之一，我们不追求规模，价格合适我们就做，不合适我们就不做，这个态度，保险行业大多数保险公司做不到我们这样，三个条件允许我们灵活，我们这个政策对股东好，对整个行业也挺好，别人不敢做的时候我们供应 capacity，所以对买家经纪人需要我们，我们有生意做，我们政策没问题。</p><p>1987年我们承保结果很好，综合成本率105，比1986年103略高一点，但是我们浮存金更多，所以我们盈利改善，因为我们拿到更多浮存金，未来几年，我们浮存金比例上升，所以1988 1989综合成本率上升，我们保险利润还会 improve，因为更多浮存金带来更多投资收益。</p><p>我们保险过去几年，我们也拿到不少非财务收益，迈克·戈德堡招了很多专业人才，现在准备好了接更大风险，所以我们未来会抓住机会。</p><p>但是，我们做很多长尾业务，很多年才能知道准备金对不对，一年准备金开发，所以你现在看，我们前几年错了，连续三年错了，所以你要小心，会计师每年都会错，不可能准，我们多年之后才知道，所以现在我们尽量准确，还是要小心，我们这个行业，骗人很常见，错了就是错了，我们也会错，但是错了我们就承认改，这个没办法，长尾保险就是这样， auditor 没办法准。</p><p>我们现在观点，很多骗子就利用这个，长期尾业务，故意低估准备金，虚假报告盈利，这种骗人，未来还会有，所以投资者小心。</p><h2 id="可交易证券——永久持仓" tabindex="-1">可交易证券——永久持仓 <a class="header-anchor" href="#可交易证券——永久持仓" aria-label="Permalink to &quot;可交易证券——永久持仓&quot;">​</a></h2><p>查理和我买普通股给伯克希尔，就像我们买生意，我们看 business 前景，看管理，看价格，我们没打算什么时候卖，我们愿意一直拿着，只要 business 内在价值能满意增长，我们投资就像我们就是 business 买家，不是市场分析师，不是宏观分析师，也不是证券分析师。</p><p>本<a href="/04_people/本·格雷厄姆.html">本·格雷厄姆</a>我的老师，很久以前说过，市场先生比喻，最适合投资成功心态，你想象你跟市场先生，每天给你报价，你是合伙人，他每天来给你报价买你股份卖你股份，他情绪不稳定，他有时候 euphoria 开心，给你很高价格，有时候 depressed 抑郁，很低价格，你完全可以不理他，利用他价格，你不需要跟着他疯，你越不听他，他对你有用，如果你被他影响，你就错了，因为你跟着他错了，你就错了，灰姑娘参加 ball，最后一切都会变成南瓜老鼠，所以记住，灰姑娘说，记住一个警告：市场先生是给你服务，不是给你指导，你用他口袋，不是用他智慧，他疯你要么ignored，没用他不是 guide，你如果被他影响，你就完蛋，就是输家，扑克说，如果你在桌子坐了三十分钟，你不知道谁是傻瓜，你就是傻瓜。</p><p>本这个寓言现在投资世界流行有效市场动态对冲这些，看起来过时，我觉得依然有效，现在华尔街，大家喜欢复杂公式 beta，这些东西对投资者没用，这些东西没用，投资成功不是来自复杂公式，来自好 judgment，你要情绪不被感染，你得明白，短期市场投票机，长期称重机，你企业内在价值涨得满意增长，足够了，延迟认可没关系，你还能便宜买到更多好东西。当然有时候市场会高估，我们会卖，当然有时候我们需要钱买更便宜，我们错了我们也卖，但是我们主要就是买了就拿着不动，我们三大重仓就是这样，就是看好，我们不卖，哪怕高估我们也不卖，就像我们完全控股 business，我们不卖，除非价格够高我们才卖，所以这种态度对我们挺好，我们风格 eccentric，我们就喜欢这样，我们这种性格，我们和我们喜欢的人在一起，我们不愿意换，换来换去不会变不好，我们不像华尔街现在所有人都把公司股票当作交易商品，我们就是 permanent 就是我们生活方式，我们觉得这样挺好。</p><p>我们三大永久持仓：</p><table tabindex="0"><thead><tr><th>公司名称</th><th>持股数</th><th>成本（百万省略）</th><th>市值（百万省略）</th></tr></thead><tbody><tr><td>首都城市/ABC</td><td>3,000,000</td><td>517.5</td><td>1035</td></tr><tr><td>GEICO</td><td>6,850,000</td><td>45.7</td><td>756</td></tr><tr><td>华盛顿邮报</td><td>1,727,765</td><td>9.7</td><td>326</td></tr></tbody></table><p>我们买控股 business，还是买部分股权，根本没区别，我们就是买 business 长期前景好，价格合理，管理好，我们不交易，我们就是这样，我们做成 silk purse 从 silk 做，猪耳朵做不成 silk purse，我们失败过，我二十年才明白，你买好 business 才对，我以前找便宜烂 business，最后惩罚就是给我教训了。</p><p>当然我们控股优势，第一你能影响资本配置，控股你能换 management，错了，实际上很多CEO不懂资本配置，大多数CEO升到顶了，他们本来别的地方做好了，很多CEO，升到CEO错了，所以很多CEO升到顶，不懂资本配置，这不是什么秘密，很多CEO升上来，他们在营销生产工程，这些领域做好了，然后 CEO 他们不懂资本配置，很多企业利润留存下来，十年之后，很多公司留存收益，百分之十净值得，十年之后，很多都赚了很多，大部分财富增加了，很多利润留存都分配好了，所以，大多数CEO不懂资本配置，很多时候，确实，很多，很多。</p><p>第二个控股优势税收，我们控股80%以上控股，税收比少数股权低，最近税法改了，现在更差了，税法改了之后，少数股权税收现在更重了，所以我们控股比少数股权更好，当然少数股权好处就是有时候市场给你机会， extraordinary business extraordinary 价格，你买到 extraordinary business 真不贵，我们买了，谁买不到控股权，你买不到 whole business，二级市场能买到 minority，比如我们华盛顿邮报，1973买，每股五块六分钱，现在税后每股赚十块三毛，所以市场先生就是好朋友，给我们机会，买到 extraordinary 价格买 extraordinary business，当然这种好事。</p><p>有趣会计 irony，我们控股企业，会计不把所有收益，三大股票市场价值超过二十亿，但是我们会计只拿到股息，赚了一亿一千万，我们持有 minority，这些 business 就是，账面价值只算股息，但是 value 就是市场价格，会计规则就是这样，控股 business 我们资产负债表按市价，我们 minority 就是只算股息，所以会计就是，我们没放进去，内在价值早就增值了，不算进去，我们 mental 也不管，我们不管GAAP怎么算，我们看 business 赚钱，我们就是赚钱就是，内在价值增长，我们不管GAAP怎么算，我们觉得我们方法挺好。</p><h2 id="可交易证券——其他" tabindex="-1">可交易证券——其他 <a class="header-anchor" href="#可交易证券——其他" aria-label="Permalink to &quot;可交易证券——其他&quot;">​</a></h2><p>除了三个永久持仓，我们还有其他分类，我们选股，五大类，我们没偏见，找最高税后期望回报，我们不追求 immediate report 收益最大化，我们 goal 就是 long-term net worth 最大化。</p><p>看普通股，1987年股市很兴奋，最后十月崩盘，道指年底涨2.3%，专业投资者搞出来这个结果，专业投资者，很多大机构投资者，不看企业未来，天天看别人接下来干什么，所以波动就是疯狂，很多大牌投资顾问，流行什么投资组合保险，就是价格跌了，只要跌一点，自动卖，十月中旬，都说600-900亿美元等着触发卖，所以为什么市场崩盘，为什么崩成这样，普通人，结论就是，市场先生疯了，给真正投资者更好机会，价格跌了，真投资者更有机会买便宜买好货。</p><p>我们十月跌了，我们看到价格跌动心了想买，没来得及买多少就涨回去了，年底我们没买大投资，所以年底没大投资，市场先生肯定还会发疯，我们等着，机会来的时候我们会买，我们肯定会有机会。</p><p>我们现在我们大部分钱放中期免税债券，现在我们拿着九亿，大部分老的，大部分享受免税，还赚不少，我们现在不喜欢长期债券，因为货币长期债券不好，所以我们不喜欢，我们还是看不上，我们对，我们愿意投一点点。</p><p>我们继续厌恶长期债券，我们怀疑美元，因为我们贸易逆差外国人拿了很多 our claim check，就是债券存款什么，外国人default，美国 default 最后通胀稀释，所以我们相信外国人，我们还是怕，现在政府 default 就是 Blanche DuBois，说我一直靠陌生人善心，我们欠外国人等着，外国人相信我们 integrity，我们最后肯定通胀，所以我们长期债券不喜欢。</p><p>套利，我们过去做的不错，一年没遇到大错，平均税前25%，当然一两次坏的就能改变结果，我们一年做几笔，我们不做很多，我们只做宣布并购的，不赌未来，所以我们结果不错，我们不参与绿票讹诈，所以我们1987年底我们只有一个五千多万股Allegis，七十多亿成本，价值七十八亿。</p><p>我们Texaco破产之后我们买了它债券，价格很低，我们觉得最差情况我们也付得起，结果肯定比现在价格高，年底账面价值一亿零四百万，市值一亿一千九百万。</p><h2 id="我们1987年我们拿了七亿所罗门兄弟9-可转优先股-我们没有对投行未来我们没看法-我们喜欢约翰·古弗兰德董事长-我们认识他1976年geico快破产-他帮了大忙-他人品我们信得过-我们觉得这个生意我们愿意合伙-所以我们买了-年底我们价值九十八-percent-面值-亏一千四百万-我们觉得-他做的好-未来肯定会好。" tabindex="-1">我们1987年我们拿了七亿所罗门兄弟9%可转优先股，我们没有对投行未来我们没看法，我们喜欢约翰·古弗兰德董事长，我们认识他1976年GEICO快破产，他帮了大忙，他人品我们信得过，我们觉得这个生意我们愿意合伙，所以我们买了，年底我们价值九十八 percent 面值，亏一千四百万，我们觉得，他做的好，未来肯定会好。 <a class="header-anchor" href="#我们1987年我们拿了七亿所罗门兄弟9-可转优先股-我们没有对投行未来我们没看法-我们喜欢约翰·古弗兰德董事长-我们认识他1976年geico快破产-他帮了大忙-他人品我们信得过-我们觉得这个生意我们愿意合伙-所以我们买了-年底我们价值九十八-percent-面值-亏一千四百万-我们觉得-他做的好-未来肯定会好。" aria-label="Permalink to &quot;我们1987年我们拿了七亿所罗门兄弟9%可转优先股，我们没有对投行未来我们没看法，我们喜欢约翰·古弗兰德董事长，我们认识他1976年GEICO快破产，他帮了大忙，他人品我们信得过，我们觉得这个生意我们愿意合伙，所以我们买了，年底我们价值九十八 percent 面值，亏一千四百万，我们觉得，他做的好，未来肯定会好。&quot;">​</a></h2><h2 id="总结-总结完了-我们这里说了-我们肯定-我们不提前说-我们持仓会变-我们不说-我们也不评论-rumors。" tabindex="-1">总结，总结完了，我们这里说了，我们肯定，我们不提前说，我们持仓会变，我们不说，我们也不评论 rumors。 <a class="header-anchor" href="#总结-总结完了-我们这里说了-我们肯定-我们不提前说-我们持仓会变-我们不说-我们也不评论-rumors。" aria-label="Permalink to &quot;总结，总结完了，我们这里说了，我们肯定，我们不提前说，我们持仓会变，我们不说，我们也不评论 rumors。&quot;">​</a></h2><h2 id="融资" tabindex="-1">融资 <a class="header-anchor" href="#融资" aria-label="Permalink to &quot;融资&quot;">​</a></h2><p>年底后我们发了两亿五千万债券，2018到期，十年后偿债基金，我们平均利息超过10%，所罗门做投行服务很好。</p><p>我们对通胀悲观，但是我们不喜欢太多债务，我们想要足够好结果要 extra return，我们不要为了未来机会留着，我们愿意借钱等着机会，机会来的时候我们有钱，所以我们借钱等着。我们原则就是，我们不希望杠杆太高风险，我们要一定不会，我们不喜欢借钱借钱借钱，我们不会风险不对，我们不要额外回报不重要，我们一定要确定，最坏情况我们也能应对，我们才借钱，我们从来我们不对。</p><h2 id="不对-我们不会为了-extra-赚更多-我们不会拿重要东西冒风险-我们不对-不对-没关系-我们错了我们也能接受-不对-不对-不对。" tabindex="-1">不对，我们不会为了 extra 赚更多，我们不会拿重要东西冒风险，我们不对，不对，没关系，我们错了我们也能接受，不对，不对，不对。 <a class="header-anchor" href="#不对-我们不会为了-extra-赚更多-我们不会拿重要东西冒风险-我们不对-不对-没关系-我们错了我们也能接受-不对-不对-不对。" aria-label="Permalink to &quot;不对，我们不会为了 extra 赚更多，我们不会拿重要东西冒风险，我们不对，不对，没关系，我们错了我们也能接受，不对，不对，不对。&quot;">​</a></h2><p>我们进一步，我们策略就是，机会来了提前借钱等着机会，机会来了我们等着，我们借钱等着机会来了我们拿着钱，这个对不对，不对，我们就是，我们就是，这个，我们就是，我们，就是这样，机会多的时候钱便宜不行，没机会的时候我们等着，等着坏的时候机会，所以我们攒钱等着。</p><h2 id="收购广告" tabindex="-1">收购广告 <a class="header-anchor" href="#收购广告" aria-label="Permalink to &quot;收购广告&quot;">​</a></h2><p>我们想要更多这样 business，像我们已经买的，我们标准：</p><p>(1) 大额收购，税后盈利至少1000万美元，</p><p>(2) 证明持续盈利能力，我们不关心未来预测，也不要扭转，</p><p>(3) ROE好，负债少最好没有负债，</p><p>(4) 管理层在位，</p><p>(5) 业务简单，如果太复杂技术我们不懂，</p><p>(6) 报价明确，不知道价格不谈。</p><p>我们不会敌意收购，我们保密，五分钟就能给你答复，我们喜欢现金买，价格合适我们换股我们也愿意换股，我们只要我们拿到内在价值等于我们给出的。</p><p>现在我们接受潜在卖家可以找我们过去合作过的人推荐我们，我们对 right business right people 我们给你一个好家。</p><p>除了买 whole business 我们也买 negotiated 买大额 non-control block，就像我们买首都城市，我们也喜欢买可转换优先股长期投资，就像我们买所罗门。</p><h2 id="杂项" tabindex="-1">杂项 <a class="header-anchor" href="#杂项" aria-label="Permalink to &quot;杂项&quot;">​</a></h2><p>1987年，97.2%合格股份参与股东指定捐赠，一共捐了490万美元，两千零五十家慈善收到捐款。最近调查说，大公司，一半公司董事捐董事喜欢董事喜欢让董事捐，股东从来没有问过股东喜欢捐哪里，我们觉得很奇怪，股东出钱，为什么管理者捐，董事捐，股东自己选，为什么董事捐，为什么股东出钱，董事说了算，这就是政治，你拿A钱，给C，这就是税收，董事就是慈善，我们认为应该股东自己决定钱捐给谁，不是经理人董事捐，我们就是这样，股东就是股东决定。</p><p>我们敦促新股东读一下项目描述，如果你想参与，一定要马上把股票登记在你自己名下，不要券商 nominee，1988年9月30日没登记不能参与1988年项目。</p><p>去年年会大概四百五十人参加，问题都很好，今年五月二十三日奥马哈见你一定要来，年会之后我们还有大巴去NFM，<a href="/04_people/B夫人.html">B夫人</a>期待你买东西，去年买了四万美元，<a href="/04_people/B夫人.html">B夫人</a>说我今年一定要超过这个数字，你去帮我证明我不对，所以你一定要来，帮我证明你不对，她不会让你失望。</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，董事长<br> 董事会主席</p>',87)])])}const c=e(p,[["render",o]]);export{b as __pageData,c as default};
